from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_2, WORKLOAD_3
import time
import random
import collections

def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[float, list[int]]:
    n = workload.num_txns
    if n == 0:
        return 0.0, []

    txns = workload.txns
    write_counts = [0] * n
    read_counts = [0] * n
    write_sets = [set() for _ in range(n)]
    read_sets = [set() for _ in range(n)]

    for i in range(n):
        for op_type, key, pos, txn_len in txns[i]:
            if op_type == 'w':
                write_counts[i] += 1
                write_sets[i].add(key)
            else:
                read_counts[i] += 1
                read_sets[i].add(key)

    key_write_counts = collections.defaultdict(int)
    key_read_counts = collections.defaultdict(int)

    for i in range(n):
        for key in write_sets[i]:
            key_write_counts[key] += 1
        for key in read_sets[i]:
            key_read_counts[key] += 1

    conflict_scores = [0] * n
    for i in range(n):
        score = 0
        for key in write_sets[i]:
            score += (key_write_counts[key] - 1) * 10
            score += key_read_counts[key] * 5
        for key in read_sets[i]:
            score += key_write_counts[key] * 5
        conflict_scores[i] = score

    best_makespan = float('inf')
    best_schedule = None

    for attempt in range(min(num_seqs, 15)):
        if attempt == 0:
            schedule = _bucket_sort(conflict_scores, ascending=True)
        elif attempt == 1:
            schedule = _bucket_sort(write_counts, ascending=True)
        elif attempt == 2:
            schedule = _bucket_sort(write_counts, ascending=False)
        elif attempt == 3:
            schedule = _bucket_sort(conflict_scores, ascending=False)
        elif attempt == 4:
            schedule = _greedy_construction(workload, 'conflict')
        elif attempt == 5:
            schedule = _greedy_construction(workload, 'write')
        elif attempt == 6:
            schedule = list(range(n))
        elif attempt == 7:
            schedule = list(range(n))
            random.shuffle(schedule)
        elif attempt == 8:
            schedule = _bucket_sort([write_counts[i] * 3 + read_counts[i] for i in range(n)], ascending=True)
        elif attempt == 9:
            schedule = _bucket_sort([write_counts[i] * 3 + read_counts[i] for i in range(n)], ascending=False)
        elif attempt == 10:
            schedule = _greedy_construction(workload, 'hybrid')
        elif attempt == 11:
            schedule = _bucket_sort([len(write_sets[i]) * 10 + len(read_sets[i]) for i in range(n)], ascending=True)
        elif attempt == 12:
            schedule = _bucket_sort([len(write_sets[i]) * 10 + len(read_sets[i]) for i in range(n)], ascending=False)
        elif attempt == 13:
            schedule = _reverse_if_better(workload, list(range(n)))
        else:
            schedule = _bucket_sort([conflict_scores[i] + random.randint(0, 10) for i in range(n)], ascending=True)

        makespan = workload.get_opt_seq_cost(schedule)
        if makespan < best_makespan:
            best_makespan = makespan
            best_schedule = schedule

    return best_makespan, best_schedule

def _bucket_sort(values: list[int], ascending: bool) -> list[int]:
    if not values:
        return []

    min_val = min(values)
    max_val = max(values)
    range_size = max_val - min_val + 1

    if range_size > 10000:
        indices = list(range(len(values)))
        indices.sort(key=lambda i: values[i])
        return indices if ascending else indices[::-1]

    buckets = [[] for _ in range(range_size)]
    for i, val in enumerate(values):
        buckets[val - min_val].append(i)

    result = []
    if ascending:
        for bucket in buckets:
            result.extend(bucket)
    else:
        for bucket in reversed(buckets):
            result.extend(bucket)

    return result

def _greedy_construction(workload: Workload, strategy: str) -> list[int]:
    n = workload.num_txns
    txns = workload.txns

    write_sets = [set() for _ in range(n)]
    read_sets = [set() for _ in range(n)]

    for i in range(n):
        for op_type, key, pos, txn_len in txns[i]:
            if op_type == 'w':
                write_sets[i].add(key)
            else:
                read_sets[i].add(key)

    remaining = set(range(n))
    schedule = []

    active_writes = set()
    active_reads = set()

    while remaining:
        best_txn = -1
        best_score = float('inf') if strategy != 'write' else -1

        for txn in remaining:
            if strategy == 'conflict':
                conflict = len(write_sets[txn].intersection(active_writes))
                conflict += len(write_sets[txn].intersection(active_reads))
                conflict += len(read_sets[txn].intersection(active_writes))
                score = conflict
            elif strategy == 'write':
                score = len(write_sets[txn])
            elif strategy == 'hybrid':
                write_conflict = len(write_sets[txn].intersection(active_writes.union(active_reads)))
                read_conflict = len(read_sets[txn].intersection(active_writes))
                score = write_conflict * 3 + read_conflict
            else:
                score = 0

            if (strategy == 'write' and score > best_score) or (strategy != 'write' and score < best_score):
                best_score = score
                best_txn = txn
            elif score == best_score and random.random() < 0.3:
                best_txn = txn

        if best_txn == -1:
            best_txn = next(iter(remaining))

        schedule.append(best_txn)
        remaining.remove(best_txn)

        active_writes.update(write_sets[best_txn])
        active_reads.update(read_sets[best_txn])

    return schedule

def _reverse_if_better(workload: Workload, schedule: list[int]) -> list[int]:
    makespan = workload.get_opt_seq_cost(schedule)
    reversed_schedule = schedule[::-1]
    reversed_makespan = workload.get_opt_seq_cost(reversed_schedule)

    return reversed_schedule if reversed_makespan < makespan else schedule

def get_random_costs() -> tuple[float, list[list[int]], float]:
    random.seed(42)
    start_time = time.time()

    total_makespan = 0.0
    all_schedules = []

    for workload_data in [WORKLOAD_1, WORKLOAD_2, WORKLOAD_3]:
        workload = Workload(workload_data)
        makespan, schedule = get_best_schedule(workload, 15)
        total_makespan += makespan
        all_schedules.append(schedule)

    execution_time = time.time() - start_time
    return total_makespan, all_schedules, execution_time

