import random
import time

def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[int, list[int]]:
    n = workload.num_txns
    if n == 0:
        return 0, []

    txns = workload.txns

    # Precompute key access frequencies
    key_write_freq = {}
    key_read_freq = {}
    for i in range(n):
        for op_type, key, _, _ in txns[i]:
            if op_type == 'w':
                key_write_freq[key] = key_write_freq.get(key, 0) + 1
            else:
                key_read_freq[key] = key_read_freq.get(key, 0) + 1

    # Precompute transaction conflict scores
    conflict_scores = [0] * n
    for i in range(n):
        score = 0
        for op_type, key, _, _ in txns[i]:
            if op_type == 'w':
                score += key_write_freq.get(key, 0) * 2
                score += key_read_freq.get(key, 0)
            else:
                score += key_write_freq.get(key, 0)
        conflict_scores[i] = score

    best_cost = float('inf')
    best_schedule = None

    # Try multiple construction strategies
    for attempt in range(num_seqs):
        remaining = list(range(n))
        idx_map = {i: i for i in range(n)}
        schedule = []

        # Track conflicts incrementally
        key_written = set()
        key_read = set()

        def remove(txn_id: int) -> None:
            pos = idx_map[txn_id]
            last = remaining[-1]
            remaining[pos] = last
            idx_map[last] = pos
            remaining.pop()
            del idx_map[txn_id]

        # Construction strategy based on attempt number
        if attempt % 3 == 0:
            # Low conflict first strategy
            remaining.sort(key=lambda x: conflict_scores[x])
        elif attempt % 3 == 1:
            # High conflict first strategy
            remaining.sort(key=lambda x: -conflict_scores[x])
        else:
            # Random order
            random.shuffle(remaining)

        # Rebuild idx_map after sorting/shuffling
        idx_map = {txn_id: i for i, txn_id in enumerate(remaining)}

        for step in range(n):
            best_candidate = None
            best_candidate_cost = float('inf')

            # Evaluate only first K candidates (O(1) per step)
            K = min(5, len(remaining))
            candidates = remaining[:K]

            for cand in candidates:
                # Quick conflict estimation
                conflicts = 0
                for op_type, key, _, _ in txns[cand]:
                    if op_type == 'w':
                        if key in key_written or key in key_read:
                            conflicts += 1
                    else:
                        if key in key_written:
                            conflicts += 1

                # Prefer transactions with fewer conflicts
                if conflicts < best_candidate_cost:
                    best_candidate_cost = conflicts
                    best_candidate = cand

            if best_candidate is None:
                best_candidate = remaining[0]

            schedule.append(best_candidate)

            # Update conflict tracking
            for op_type, key, _, _ in txns[best_candidate]:
                if op_type == 'w':
                    key_written.add(key)
                else:
                    key_read.add(key)

            remove(best_candidate)

        # Evaluate final schedule
        cost = workload.get_opt_seq_cost(schedule)
        if cost < best_cost:
            best_cost = cost
            best_schedule = schedule

    return best_cost, best_schedule if best_schedule else list(range(n))

def get_random_costs() -> tuple[int, list[list[int]], float]:
    random.seed(42)
    start_time = time.time()

    total_makespan = 0
    schedules = []

    for wl_data in (WORKLOAD_1, WORKLOAD_2, WORKLOAD_3):
        workload = Workload(wl_data)
        makespan, schedule = get_best_schedule(workload, 15)
        total_makespan += makespan
        schedules.append(schedule)

    elapsed = time.time() - start_time
    return total_makespan, schedules, elapsed

