def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[float, list[int]]:
    n = workload.num_txns
    txns = [workload.txns[i] for i in range(n)]

    last_writer = {}
    dependents = [[] for _ in range(n)]
    indegree = [0] * n

    for i, ops in enumerate(txns):
        for op_type, key, _, _ in ops:
            if op_type == 'w':
                if key in last_writer:
                    prev = last_writer[key]
                    if prev != i:
                        dependents[prev].append(i)
                        indegree[i] += 1
                last_writer[key] = i
            elif op_type == 'r':
                if key in last_writer:
                    prev = last_writer[key]
                    if prev != i:
                        dependents[prev].append(i)
                        indegree[i] += 1

    schedule = []
    ready = [i for i in range(n) if indegree[i] == 0]
    ready_counts = [len(dependents[i]) for i in ready]

    while ready:
        best_idx = 0
        best_score = ready_counts[0]
        for idx in range(1, len(ready)):
            if ready_counts[idx] > best_score:
                best_score = ready_counts[idx]
                best_idx = idx

        txn_id = ready.pop(best_idx)
        schedule.append(txn_id)

        for dep in dependents[txn_id]:
            indegree[dep] -= 1
            if indegree[dep] == 0:
                ready.append(dep)
                ready_counts.append(len(dependents[dep]))

        del ready_counts[best_idx]

    makespan = workload.get_opt_seq_cost(schedule)
    return makespan, schedule

