from txn_simulator import Workload
from workloads import WORKLOAD_1, WORKLOAD_2, WORKLOAD_3
import time
import random
import collections

def get_best_schedule(workload: Workload, num_seqs: int) -> tuple[int, list[int]]:
    # Build dependency graph: txn i must wait for last writer of each key it accesses
    last_writer = {}
    indegree = [0] * workload.num_txns
    dependents = [[] for _ in range(workload.num_txns)]

    for txn_id in range(workload.num_txns):
        ops = workload.txns[txn_id]
        # Find all keys this transaction accesses
        accessed_keys = set()
        for op_type, key, pos, txn_len in ops:
            accessed_keys.add(key)

        # For each accessed key, check last writer
        for key in accessed_keys:
            if key in last_writer:
                writer = last_writer[key]
                if writer != txn_id:
                    indegree[txn_id] += 1
                    dependents[writer].append(txn_id)

        # Update last_writer for keys this transaction writes to
        for op_type, key, pos, txn_len in ops:
            if op_type == 'w':
                last_writer[key] = txn_id

    # Topological sort with priority based on operation count
    ready = collections.deque()
    for i in range(workload.num_txns):
        if indegree[i] == 0:
            ready.append(i)

    schedule = []
    # Precompute operation counts for prioritization
    op_counts = [len(workload.txns[i]) for i in range(workload.num_txns)]

    while ready:
        # Select transaction with smallest operation count to prioritize shorter ones
        min_idx = 0
        for i in range(1, len(ready)):
            if op_counts[ready[i]] < op_counts[ready[min_idx]]:
                min_idx = i
        current = ready[min_idx]
        # Remove from ready list
        if min_idx == 0:
            ready.popleft()
        elif min_idx == len(ready) - 1:
            ready.pop()
        else:
            ready = collections.deque(list(ready)[:min_idx] + list(ready)[min_idx+1:])

        schedule.append(current)

        # Update indegree of dependents
        for dep in dependents[current]:
            indegree[dep] -= 1
            if indegree[dep] == 0:
                ready.append(dep)

    # Fallback if topological sort fails (shouldn't happen with valid workloads)
    if len(schedule) < workload.num_txns:
        schedule = list(range(workload.num_txns))

    makespan = workload.get_opt_seq_cost(schedule)
    return makespan, schedule

def get_random_costs() -> tuple[int, list[list[int]], float]:
    start_time = time.time()
    total_makespan = 0
    all_schedules = []

    for workload_data in [WORKLOAD_1, WORKLOAD_2, WORKLOAD_3]:
        workload = Workload(workload_data)
        makespan, schedule = get_best_schedule(workload, 10)
        total_makespan += makespan
        all_schedules.append(schedule)

    execution_time = time.time() - start_time
    return total_makespan, all_schedules, execution_time
